# Step 1: Identify your entities (nouns in the problem)
# Step 2: Identify operations (verbs in the problem)
# Step 3: Choose storage structures
# Step 4: Design the Manager class API

# Example: In-Memory Database problem
# Entities: Record (key, value, optional TTL)
# Operations: SET, GET, DELETE, SCAN, SET_WITH_TTL
# Storage: dict[str, Record]
# Manager: Database class

from dataclasses import dataclass, field
from typing import Optional
import time

@dataclass
class Record:
    key: str
    value: str
    expires_at: Optional[float] = None

    def is_alive(self, now: float) -> bool:
        return self.expires_at is None or now < self.expires_at

class Database:
    def __init__(self):
        self._store: dict[str, Record] = {}

    def set(self, key: str, value: str) -> None:
        self._store[key] = Record(key=key, value=value)

    def get(self, key: str) -> Optional[str]:
        record = self._store.get(key)
        if record is None or not record.is_alive(time.time()):
            return None
        return record.value

# BAD: mixing TTL logic into Database
class DatabaseBad:
    def get(self, key: str) -> Optional[str]:
        record = self._store.get(key)
        if record is None:
            return None
        # TTL logic buried in get() — hard to extend
        if record.get("expires_at") and time.time() > record["expires_at"]:
            del self._store[key]
            return None
        return record["value"]

# GOOD: TTL logic in Record, Database stays clean
class DatabaseGood:
    def get(self, key: str) -> Optional[str]:
        record = self._store.get(key)
        if record is None or not record.is_alive(time.time()):
            if record:
                del self._store[key]  # lazy cleanup
            return None
        return record.value

from typing import Optional
from copy import deepcopy

class Database:
    def __init__(self):
        self._store: dict[str, str] = {}
        self._transaction: Optional[dict[str, str]] = None

    def begin(self) -> None:
        """Start a transaction — snapshot current state."""
        self._transaction = deepcopy(self._store)

    def set(self, key: str, value: str) -> None:
        target = self._transaction if self._transaction is not None else self._store
        target[key] = value

    def get(self, key: str) -> Optional[str]:
        target = self._transaction if self._transaction is not None else self._store
        return target.get(key)

    def commit(self) -> None:
        """Apply transaction changes to main store."""
        if self._transaction is not None:
            self._store = self._transaction
            self._transaction = None

    def rollback(self) -> None:
        """Discard transaction changes."""
        self._transaction = None

db = Database()
db.set("x", "1")
db.begin()
db.set("x", "2")
db.set("y", "3")
print(db.get("x"))   # 2 (inside transaction)
db.rollback()
print(db.get("x"))   # 1 (rolled back)
print(db.get("y"))   # None (never committed)

from copy import deepcopy
from typing import Optional

class Database:
    def __init__(self):
        self._store: dict[str, str] = {}
        self._tx_stack: list[dict[str, str]] = []

    def begin(self) -> None:
        current = self._tx_stack[-1] if self._tx_stack else self._store
        self._tx_stack.append(deepcopy(current))

    def set(self, key: str, value: str) -> None:
        target = self._tx_stack[-1] if self._tx_stack else self._store
        target[key] = value

    def get(self, key: str) -> Optional[str]:
        target = self._tx_stack[-1] if self._tx_stack else self._store
        return target.get(key)

    def commit(self) -> None:
        if not self._tx_stack:
            return
        committed = self._tx_stack.pop()
        if self._tx_stack:
            self._tx_stack[-1].update(committed)
        else:
            self._store = committed

    def rollback(self) -> None:
        if self._tx_stack:
            self._tx_stack.pop()

db = Database()
db.set("a", "1")
db.begin()
db.set("a", "2")
db.begin()
db.set("a", "3")
db.rollback()         # inner rollback
print(db.get("a"))    # 2
db.commit()           # outer commit
print(db.get("a"))    # 2

from dataclasses import dataclass, field

@dataclass
class Account:
    account_id: str
    balance: float = 0.0
    annual_interest_rate: float = 0.0   # e.g. 0.05 = 5% p.a.


class Bank:
    """Minimal Bank focused on compound-interest accrual (ICA L6 topic)."""

    def __init__(self):
        self._accounts: dict[str, Account] = {}

    def create_account(self, account_id: str) -> bool:
        if account_id in self._accounts:
            return False
        self._accounts[account_id] = Account(account_id)
        return True

    def deposit(self, account_id: str, amount: float) -> float:
        if account_id not in self._accounts:
            return -1
        self._accounts[account_id].balance += amount
        return self._accounts[account_id].balance

    def get_balance(self, account_id: str) -> float:
        if account_id not in self._accounts:
            return -1
        return self._accounts[account_id].balance

    def set_interest_rate(self, account_id: str, annual_rate: float) -> None:
        """Set annual interest rate (e.g. 0.05 = 5%)."""
        if account_id in self._accounts:
            self._accounts[account_id].annual_interest_rate = annual_rate

    def accrue_interest(self, days: int) -> dict:
        """
        Apply compound interest for `days` days to all interest-bearing accounts.
        Returns {account_id: interest_earned} for accounts with rate > 0.
        Returns {} immediately if days <= 0.
        """
        if days <= 0:
            return {}

        result: dict[str, float] = {}
        for account_id, acc in self._accounts.items():
            if acc.annual_interest_rate == 0.0:
                continue                           # skip non-interest accounts

            daily_rate = acc.annual_interest_rate / 365
            old_balance = acc.balance
            # Compound interest formula: P * (1 + r)^n
            new_balance = old_balance * (1 + daily_rate) ** days
            interest_earned = new_balance - old_balance

            acc.balance = new_balance
            result[account_id] = interest_earned

        return result


# Verification
bank = Bank()
bank.create_account("alice")
bank.create_account("bob")
bank.deposit("alice", 1000.0)
bank.deposit("bob",  2000.0)
bank.set_interest_rate("alice", 0.365)  # 36.5% p.a. -> 0.1% / day

# 1 day: alice earns 1000 * 0.001 = 1.0 exactly
result = bank.accrue_interest(1)
print(round(result["alice"], 2))    # 1.0
print("bob" in result)               # False  (no rate set)
print(bank.get_balance("alice") > 1000.0)   # True

# 0 days: no-op
print(bank.accrue_interest(0))       # {}

