from typing import Optional

class Ledger:
    def __init__(self):
        self._balances: dict[str, float] = {}
        self._snapshot: Optional[dict[str, float]] = None

    def begin(self) -> None:
        self._snapshot = deepcopy(self._balances)

    def credit(self, account: str, amount: float) -> None:
        target = self._snapshot if self._snapshot is not None else self._balances
        target[account] = target.get(account, 0) + amount

    def debit(self, account: str, amount: float) -> None:
        target = self._snapshot if self._snapshot is not None else self._balances
        current = target.get(account, 0)
        if current < amount:
            raise ValueError(f"Insufficient funds: {current} < {amount}")
        target[account] = current - amount

    def commit(self) -> None:
        if self._snapshot is not None:
            self._balances = self._snapshot
            self._snapshot = None

    def rollback(self) -> None:
        self._snapshot = None

    def balance(self, account: str) -> float:
        return self._balances.get(account, 0)

