import time
from dataclasses import dataclass
from typing import Optional

@dataclass
class Entry:
    value: str
    expires_at: Optional[float] = None   # Unix timestamp

    def is_valid(self, now: float) -> bool:
        return self.expires_at is None or now < self.expires_at

class TTLStore:
    def __init__(self):
        self._data: dict[str, Entry] = {}

    def set(self, key: str, value: str, ttl: Optional[float] = None) -> None:
        expires_at = time.time() + ttl if ttl is not None else None
        self._data[key] = Entry(value=value, expires_at=expires_at)

    def get(self, key: str) -> Optional[str]:
        entry = self._data.get(key)
        if entry is None:
            return None
        now = time.time()
        if not entry.is_valid(now):
            del self._data[key]   # lazy cleanup
            return None
        return entry.value

store = TTLStore()
store.set("session", "abc123", ttl=0.1)   # expires in 100ms
print(store.get("session"))               # abc123
time.sleep(0.2)
print(store.get("session"))               # None

import heapq
import time
from typing import Callable

class ScheduledAction:
    def __init__(self, trigger_at: float, action: Callable):
        self.trigger_at = trigger_at
        self.action = action

    def __lt__(self, other: 'ScheduledAction') -> bool:
        return self.trigger_at < other.trigger_at

class EventScheduler:
    def __init__(self):
        self._pending: list[ScheduledAction] = []

    def schedule(self, delay_seconds: float, action: Callable) -> None:
        trigger_at = time.time() + delay_seconds
        heapq.heappush(self._pending, ScheduledAction(trigger_at, action))

    def process_due(self) -> int:
        """Process all actions due by now. Return count processed."""
        now = time.time()
        count = 0
        while self._pending and self._pending[0].trigger_at <= now:
            event = heapq.heappop(self._pending)
            event.action()
            count += 1
        return count

