import time

@dataclass
class KVRecord:
    value: str
    expires_at: Optional[float] = None

    def is_valid(self) -> bool:
        return self.expires_at is None or time.time() < self.expires_at

class KeyValueStore:
    def __init__(self):
        self._data: dict[str, KVRecord] = {}

    def set(self, key: str, value: str, ttl: Optional[float] = None) -> None:
        expires_at = time.time() + ttl if ttl else None
        self._data[key] = KVRecord(value=value, expires_at=expires_at)

    def get(self, key: str) -> Optional[str]:
        r = self._data.get(key)
        if r is None or not r.is_valid():
            return None
        return r.value

    def delete(self, key: str) -> bool:
        return bool(self._data.pop(key, None))

    def scan(self, prefix: str) -> list[tuple[str, str]]:
        now = time.time()
        return [
            (k, r.value)
            for k, r in sorted(self._data.items())
            if k.startswith(prefix) and r.is_valid()
        ]

