class FileSystem:
    def __init__(self):
        self._files: dict = {}   # path -> content
        self._dirs: set = {"/"}  # set of directory paths

    def mkdir(self, path: str) -> bool:
        """Create directory at path. Return False if already exists."""
        if path in self._dirs:
            return False
        self._dirs.add(path)
        return True

    def write_file(self, path: str, content: str) -> None:
        """Write content to file at path. Overwrites if exists."""
        self._files[path] = content

    def read_file(self, path: str) -> str:
        """Return file content. Return empty string if not found."""
        return self._files.get(path, "")

    def delete(self, path: str) -> bool:
        """Delete file or empty directory. Return False if not found."""
        if path in self._files:
            del self._files[path]
            return True
        if path in self._dirs and path != "/":
            self._dirs.discard(path)
            return True
        return False

