class FileSystem:
    def __init__(self):
        self._files: dict = {}
        self._dirs: set = {"/"}

    def ls(self, path: str) -> list:
        """Return sorted names of immediate children of path."""
        if path not in self._dirs:
            return []
        prefix = path.rstrip("/") + "/"   # e.g. "/docs/"
        results = set()
        for f in self._files:
            if f.startswith(prefix):
                rest = f[len(prefix):]       # "readme.txt" or "sub/file.txt"
                if "/" not in rest:          # immediate child only
                    results.add(rest)
        for d in self._dirs:
            if d != path and d.startswith(prefix):
                rest = d[len(prefix):]
                if "/" not in rest:
                    results.add(rest)
        return sorted(results)               # O(k log k)

    def get_size(self, path: str) -> int:
        """File: len(content). Directory: total bytes under it."""
        if path in self._files:
            return len(self._files[path])
        if path in self._dirs:
            prefix = path.rstrip("/") + "/"
            return sum(len(c) for f, c in self._files.items()
                       if f.startswith(prefix))  # O(N)
        return 0

    def find(self, root: str, name: str) -> list:
        """Return sorted full paths under root whose basename == name."""
        results = []
        prefix = root.rstrip("/") + "/"
        for f in self._files:
            if f.startswith(prefix) or f == root:
                if f.rsplit("/", 1)[-1] == name:
                    results.append(f)
        for d in self._dirs:
            if (d.startswith(prefix) or d == root) and d != root:
                if d.rsplit("/", 1)[-1] == name:
                    results.append(d)
        return sorted(results)               # O(N log N)

