class FileSystem:
    def __init__(self):
        self._files: dict = {}
        self._dirs: set = {"/"}

    def move(self, src: str, dst: str) -> bool:
        """Move file or directory. Return False on failure."""
        if src not in self._files and src not in self._dirs:
            return False
        if dst in self._files or dst in self._dirs:
            return False

        if src in self._files:
            self._files[dst] = self._files.pop(src)   # O(1)
        else:
            # Move directory: rekey dir and all contents
            self._dirs.discard(src)
            self._dirs.add(dst)
            src_prefix = src.rstrip("/") + "/"
            dst_prefix = dst.rstrip("/") + "/"
            # Snapshot before iterating (avoid mutation during iteration)
            for d in [d for d in self._dirs if d.startswith(src_prefix)]:
                self._dirs.discard(d)
                self._dirs.add(dst_prefix + d[len(src_prefix):])
            for f, c in [(f, c) for f, c in self._files.items()   # O(N)
                         if f.startswith(src_prefix)]:
                del self._files[f]
                self._files[dst_prefix + f[len(src_prefix):]] = c
        return True

    def copy(self, src: str, dst: str) -> bool:
        """Deep-copy file or directory. Return False on failure."""
        if src not in self._files and src not in self._dirs:
            return False
        if dst in self._files or dst in self._dirs:
            return False

        if src in self._files:
            self._files[dst] = self._files[src]        # O(1)
        else:
            self._dirs.add(dst)
            src_prefix = src.rstrip("/") + "/"
            dst_prefix = dst.rstrip("/") + "/"
            for d in list(self._dirs):                  # O(D)
                if d.startswith(src_prefix):
                    self._dirs.add(dst_prefix + d[len(src_prefix):])
            for f, c in list(self._files.items()):     # O(N)
                if f.startswith(src_prefix):
                    self._files[dst_prefix + f[len(src_prefix):]] = c
        return True

