class FileSystem:
    def __init__(self):
        self._files: dict = {}
        self._dirs: set = {"/"}
        self._owners: dict = {}   # path -> owner
        self._modes: dict = {}    # path -> mode string

    def set_owner(self, path: str, owner: str) -> None:
        self._owners[path] = owner

    def set_mode(self, path: str, mode: str) -> None:
        self._modes[path] = mode

    def can_read(self, path: str, user: str) -> bool:
        # Owner always has read access
        if self._owners.get(path) == user:
            return True
        # No mode set -> world-readable by default
        mode = self._modes.get(path)
        if mode is None:
            return True
        return mode[0] == 'r'          # first char controls world read

    def can_write(self, path: str, user: str) -> bool:
        # Owner always has write access
        if self._owners.get(path) == user:
            return True
        # No mode set -> world-writable by default
        mode = self._modes.get(path)
        if mode is None:
            return True
        return len(mode) > 1 and mode[1] == 'w'  # second char controls world write

