from collections import deque
from dataclasses import dataclass, field

@dataclass
class SlidingRateLimiter:
    max_requests: int
    window_ms: int
    _logs: dict = field(default_factory=dict)
    _custom_limits: dict = field(default_factory=dict)  # user_id -> limit

    def _get_log(self, user_id: str) -> deque:
        if user_id not in self._logs:
            self._logs[user_id] = deque()
        return self._logs[user_id]

    def _get_limit(self, user_id: str) -> int:
        return self._custom_limits.get(user_id, self.max_requests)

    def allow_request(self, user_id: str, timestamp: int) -> bool:
        dq = self._get_log(user_id)
        cutoff = timestamp - self.window_ms
        while dq and dq[0] <= cutoff:
            dq.popleft()
        if len(dq) >= self._get_limit(user_id):
            return False
        dq.append(timestamp)
        return True

    def get_usage(self, user_id: str, timestamp: int) -> int:
        if user_id not in self._logs:
            return 0
        dq = self._logs[user_id]
        cutoff = timestamp - self.window_ms
        while dq and dq[0] <= cutoff:
            dq.popleft()
        return len(dq)

    def set_user_limit(self, user_id: str, limit: int) -> None:
        self._custom_limits[user_id] = limit

    def get_user_limit(self, user_id: str) -> int:
        return self._custom_limits.get(user_id, self.max_requests)

