import heapq
from dataclasses import dataclass, field

@dataclass
class TaskScheduler:
    _heap: list = field(default_factory=list)
    _cancelled: set = field(default_factory=set)
    _tasks: dict = field(default_factory=dict)  # task_id -> name

    def add_task(self, task_id: str, name: str,
                 priority: int) -> bool:
        if task_id in self._tasks:
            return False                         # duplicate
        self._tasks[task_id] = name
        heapq.heappush(self._heap, (priority, task_id, name))
        return True

    def run_next(self) -> str | None:
        while self._heap:
            priority, task_id, name = heapq.heappop(self._heap)
            if task_id not in self._cancelled:
                del self._tasks[task_id]
                return name                      # executed
        return None

    def cancel_task(self, task_id: str) -> bool:
        if task_id not in self._tasks:
            return False
        self._cancelled.add(task_id)
        del self._tasks[task_id]
        return True

import heapq
from dataclasses import dataclass, field

@dataclass
class TimedScheduler:
    _heap: list = field(default_factory=list)
    _cancelled: set = field(default_factory=set)
    _tasks: dict = field(default_factory=dict)

    def add_task(self, task_id: str, name: str,
                 priority: int, run_at: int = 0) -> bool:
        if task_id in self._tasks:
            return False
        self._tasks[task_id] = (name, priority, run_at)
        # Sort by (run_at, priority) — earlier time and lower number = first
        heapq.heappush(self._heap, (run_at, priority, task_id, name))
        return True

    def run_next(self, current_time: int) -> str | None:
        while self._heap:
            run_at, priority, task_id, name = self._heap[0]
            if run_at > current_time:
                break                            # not due yet
            heapq.heappop(self._heap)
            if task_id not in self._cancelled:
                del self._tasks[task_id]
                return name
        return None

    def run_all(self, current_time: int) -> list[str]:
        results = []
        while (name := self.run_next(current_time)) is not None:
            results.append(name)
        return results

# Extended add_task to accept interval
def add_task(self, task_id: str, name: str, priority: int,
             run_at: int = 0, interval: int | None = None) -> bool:
    if task_id in self._tasks:
        return False
    self._tasks[task_id] = {
        "name": name, "priority": priority,
        "run_at": run_at, "interval": interval
    }
    heapq.heappush(self._heap, (run_at, priority, task_id, name))
    return True

def run_next(self, current_time: int) -> str | None:
    while self._heap:
        run_at, priority, task_id, name = self._heap[0]
        if run_at > current_time:
            break
        heapq.heappop(self._heap)
        if task_id in self._cancelled:
            continue
        info = self._tasks[task_id]
        if info["interval"] is not None:
            # Re-schedule recurring task
            next_run = run_at + info["interval"]
            info["run_at"] = next_run
            heapq.heappush(
                self._heap, (next_run, priority, task_id, name)
            )
        else:
            del self._tasks[task_id]         # one-shot: remove
        return name
    return None

def get_schedule(self) -> list[tuple]:
    return sorted(
        [(tid, info["run_at"]) for tid, info in self._tasks.items()
         if tid not in self._cancelled],
        key=lambda x: x[1]
    )

# This mirrors the data structures used in the ICA exercise solution.
# Workers are purely logical — no threads involved.

class WorkerPool:
    """Minimal standalone worker pool to illustrate the pattern."""

    def __init__(self):
        # worker_id -> {capacity, assigned, completed, current_tasks}
        self._workers: dict = {}
        # task_id -> worker_id  (prevents double-assignment)
        self._assigned: dict = {}
        # Simulated task queue (in the exercise this is a heap)
        self._queue: list = []  # list of (priority, task_id, name)

    def register_worker(self, worker_id: str, capacity: int) -> None:
        self._workers[worker_id] = {
            "capacity":     capacity,
            "assigned":     0,     # total ever assigned
            "completed":    0,
            "current_tasks": set(),
        }

    def add_task(self, task_id: str, name: str, priority: int) -> None:
        self._queue.append((priority, task_id, name))
        # In the exercise this is a heap push instead

    def assign_next(self, worker_id: str) -> str | None:
        if worker_id not in self._workers:
            return None
        w = self._workers[worker_id]
        if len(w["current_tasks"]) >= w["capacity"]:
            return None   # worker full

        # Find highest-priority unassigned task
        # (exercise uses a heap; here we scan for clarity)
        self._queue.sort(key=lambda x: -x[0])   # highest priority first
        for i, (priority, task_id, name) in enumerate(self._queue):
            if task_id not in self._assigned:
                self._queue.pop(i)
                self._assigned[task_id] = worker_id
                w["current_tasks"].add(task_id)
                w["assigned"] += 1
                return name    # return task NAME, not task_id
        return None

    def complete_task(self, worker_id: str, task_id: str) -> bool:
        if self._assigned.get(task_id) != worker_id:
            return False   # not assigned to this worker
        w = self._workers[worker_id]
        w["current_tasks"].discard(task_id)
        w["completed"] += 1
        del self._assigned[task_id]
        return True

    def get_worker_stats(self, worker_id: str) -> dict:
        if worker_id not in self._workers:
            return {}
        w = self._workers[worker_id]
        return {
            "assigned":  w["assigned"],
            "completed": w["completed"],
            "capacity":  w["capacity"],
        }


