class FileCache:
    def __init__(self, max_bytes: int):
        self._max_bytes = max_bytes
        self._cache: OrderedDict[str, CacheEntry] = OrderedDict()
        self._total_bytes = 0
        self._lock = threading.RLock()

    def put(self, filename: str, content: str) -> bool:
        with self._lock:
            return self._put_unlocked(filename, content)

    def get(self, filename: str) -> str:
        with self._lock:
            return self._get_unlocked(filename)

    def _put_unlocked(self, filename: str, content: str) -> bool:
        size = len(content)
        if size > self._max_bytes:
            return False
        if filename in self._cache:
            self._total_bytes -= self._cache[filename].size
            del self._cache[filename]
        while self._total_bytes + size > self._max_bytes:
            _, evicted = self._cache.popitem(last=False)
            self._total_bytes -= evicted.size
        self._cache[filename] = CacheEntry(value=content, size=size)
        self._total_bytes += size
        return True

    def _get_unlocked(self, filename: str) -> str:
        if filename not in self._cache:
            return ""
        self._cache.move_to_end(filename)
        return self._cache[filename].value

