            record = self._active_store().get(key)
            if record is None or not record.is_valid():
                return ""
            return record.value

    def delete(self, key: str) -> str:
        with self._lock:
            store = self._active_store()
            if key in store and store[key].is_valid():
                del store[key]
                return "1"
            return "0"

    def scan(self, prefix: str) -> list:
        with self._lock:
            store = self._active_store()
            return [
                (k, r.value)
                for k, r in sorted(store.items())
                if k.startswith(prefix) and r.is_valid()
            ]

    def set_many(self, pairs: list) -> None:
        with self._lock:
            store = self._active_store()
            for key, value in pairs:
