import time
from dataclasses import dataclass, field

@dataclass
class TxnRecord:
    txn_type: str
    amount: float
    balance_after: float
    timestamp: float = field(default_factory=time.time)

@dataclass
class Account:
    account_id: str
    balance: float = 0.0
    total_withdrawn: float = 0.0
    cashback_rate: float = 0.0
    history: list = field(default_factory=list)

    def record(self, txn_type: str, amount: float) -> None:
        self.history.append(TxnRecord(txn_type, amount, self.balance))

class Bank(BankBase):
    def __init__(self):
        self._accounts: dict[str, Account] = {}

    def create_account(self, account_id: str) -> bool:
        if account_id in self._accounts:
            return False
        self._accounts[account_id] = Account(account_id)
        return True

    def deposit(self, account_id: str, amount: float) -> float:
        if account_id not in self._accounts:
            return -1
        acc = self._accounts[account_id]
        acc.balance += amount
        # Apply cashback on deposit
        if acc.cashback_rate > 0:
            acc.balance += amount * acc.cashback_rate
        acc.record("deposit", amount)
        return acc.balance

    def withdraw(self, account_id: str, amount: float) -> float:
        if account_id not in self._accounts:
            return -1
        acc = self._accounts[account_id]
        if acc.balance < amount:
            return -1
        acc.balance -= amount
        acc.total_withdrawn += amount
        acc.record("withdrawal", amount)
        return acc.balance

    def get_balance(self, account_id: str) -> float:
        if account_id not in self._accounts:
            return -1
        return self._accounts[account_id].balance

    def transfer(self, from_id: str, to_id: str, amount: float) -> bool:
        if from_id not in self._accounts or to_id not in self._accounts:
            return False
        src = self._accounts[from_id]
        if src.balance < amount:
            return False
        dst = self._accounts[to_id]
        src.balance -= amount
        src.record("transfer_out", amount)
        dst.balance += amount
        dst.record("transfer_in", amount)
        return True

    def get_history(self, account_id: str) -> list:
        if account_id not in self._accounts:
            return []
        return list(reversed(self._accounts[account_id].history))

    def top_spenders(self, n: int) -> list:
        accounts = [a for a in self._accounts.values() if a.total_withdrawn > 0]
        ranked = sorted(accounts, key=lambda a: (-a.total_withdrawn, a.account_id))
        return [a.account_id for a in ranked[:n]]

    def set_cashback(self, account_id: str, rate: float) -> None:
        if account_id in self._accounts:
            self._accounts[account_id].cashback_rate = rate

