        return self._accounts[account_id].balance

    def transfer(self, from_id: str, to_id: str, amount: float) -> bool:
        if from_id not in self._accounts or to_id not in self._accounts:
            return False
        src = self._accounts[from_id]
        if src.balance < amount:
            return False
        dst = self._accounts[to_id]
        src.balance -= amount
        src.record("transfer_out", amount)
        dst.balance += amount
        dst.record("transfer_in", amount)
        return True

    def get_history(self, account_id: str) -> list:
        if account_id not in self._accounts:
            return []
        return list(reversed(self._accounts[account_id].history))

    def top_spenders(self, n: int) -> list:
        accounts = [a for a in self._accounts.values() if a.total_withdrawn > 0]
        ranked = sorted(accounts, key=lambda a: (-a.total_withdrawn, a.account_id))
        return [a.account_id for a in ranked[:n]]

    def set_cashback(self, account_id: str, rate: float) -> None:
        if account_id in self._accounts:
            self._accounts[account_id].cashback_rate = rate

    def flag_suspicious(self, account_id: str, threshold: float) -> bool:
        if account_id not in self._accounts:
            return False
        acc = self._accounts[account_id]
        if acc.balance > threshold:
            self._flagged.add(account_id)
            return True
        return False

    def get_flagged_accounts(self) -> list:
        return sorted(self._flagged)

    def batch_transfer(self, transfers: list) -> int:
        count = 0
        for from_id, to_id, amount in transfers:
            if self.transfer(from_id, to_id, amount):
                count += 1
        return count

    def set_interest_rate(self, account_id: str, annual_rate: float) -> None:
        if account_id in self._accounts:
            self._accounts[account_id].annual_interest_rate = annual_rate

    def accrue_interest(self, days: int) -> dict:
        if days <= 0:
            return {}
        result = {}
        for account_id, acc in self._accounts.items():
            if acc.annual_interest_rate == 0.0:
                continue
            daily_rate = acc.annual_interest_rate / 365
            old_balance = acc.balance
            new_balance = old_balance * (1 + daily_rate) ** days
            interest_earned = new_balance - old_balance
            acc.balance = new_balance
            result[account_id] = interest_earned
        return result

