import threading
from collections import OrderedDict
from dataclasses import dataclass

@dataclass
class CacheEntry:
    content: str
    access_count: int = 0

class FileCache(FileCacheBase):
    def __init__(self, l1_capacity: int = 10, l2_capacity: int = 20):
        self._l1_cap = l1_capacity
        self._l2_cap = l2_capacity
        self._l1: OrderedDict[str, CacheEntry] = OrderedDict()
        self._l2: OrderedDict[str, CacheEntry] = OrderedDict()
        self._l1_hits = 0
        self._l2_hits = 0
        self._total_hits = 0
        self._total_misses = 0
        self._total_size = 0  # not used but kept for interface
        self._lock = threading.RLock()

    def _evict_l1_to_l2(self):
        """Evict LRU from L1 and move to L2 (evicting L2 LRU if needed)."""
        if not self._l1:
            return
        key, entry = self._l1.popitem(last=False)
        # Remove from L2 if already there (shouldn't normally happen)
        if key in self._l2:
            del self._l2[key]
        self._l2[key] = entry
        # Evict L2 LRU if over capacity
        while len(self._l2) > self._l2_cap:
            self._l2.popitem(last=False)

    def put(self, filename: str, content: str) -> None:
        with self._lock:
            # If already in L1, update in place
            if filename in self._l1:
                self._l1.move_to_end(filename)
                self._l1[filename] = CacheEntry(content=content, access_count=self._l1[filename].access_count)
                return
            # If already in L2, remove from L2 first
            if filename in self._l2:
                del self._l2[filename]
            # If L1 has space, insert into L1
            if len(self._l1) < self._l1_cap:
                self._l1[filename] = CacheEntry(content=content)
            else:
                # L1 full — new item overflows to L2
                if filename in self._l2:
                    del self._l2[filename]
                self._l2[filename] = CacheEntry(content=content)
                # Evict L2 LRU if over capacity
                while len(self._l2) > self._l2_cap:
                    self._l2.popitem(last=False)

    def get(self, filename: str) -> str:
        with self._lock:
            # L1 hit
            if filename in self._l1:
                self._l1.move_to_end(filename)
                self._l1[filename].access_count += 1
                self._l1_hits += 1
                self._total_hits += 1
                return self._l1[filename].content
            # L2 hit — promote to L1
            if filename in self._l2:
                entry = self._l2.pop(filename)
                entry.access_count += 1
                self._l2_hits += 1
                self._total_hits += 1
                # Insert into L1; if L1 full, evict LRU to L2 first
                if len(self._l1) >= self._l1_cap:
                    self._evict_l1_to_l2()
                self._l1[filename] = entry
                return entry.content
            self._total_misses += 1
            return ""

    def get_hit_rate(self) -> float:
        total = self._total_hits + self._total_misses
        if total == 0:
            return 0.0
        return self._total_hits / total

    def get_stats(self) -> dict:
        total = self._total_hits + self._total_misses
        hit_rate = self._total_hits / total if total > 0 else 0.0
        return {
            "hits": self._total_hits,
            "misses": self._total_misses,
            "hit_rate": hit_rate,
            "size": len(self._l1) + len(self._l2),
        }

    def put_with_size(self, filename: str, content: str, size_bytes: int) -> None:
        # Not the primary feature for L6; delegate to put
        self.put(filename, content)

    def get_total_size(self) -> int:
        return len(self._l1) + len(self._l2)

    def get_access_count(self, filename: str) -> int:
        with self._lock:
            if filename in self._l1:
                return self._l1[filename].access_count
            if filename in self._l2:
                return self._l2[filename].access_count
            return 0

    def top_k_files(self, k: int) -> list:
        with self._lock:
            all_items = list(self._l1.items()) + list(self._l2.items())
            ranked = sorted(all_items, key=lambda x: (-x[1].access_count, x[0]))
            return [name for name, _ in ranked[:k]]

    def get_or_load(self, filename: str, loader_fn) -> str:
        val = self.get(filename)
        if val != "":
            return val
        content = loader_fn()
        self.put(filename, content)
        return content

    def promote(self, filename: str) -> bool:
        """Move entry from L2 to L1. Return False if not in L2."""
        with self._lock:
            if filename not in self._l2:
                return False
            entry = self._l2.pop(filename)
            # If L1 full, evict LRU to L2 first
            if len(self._l1) >= self._l1_cap:
                self._evict_l1_to_l2()
            self._l1[filename] = entry
            return True

    def get_tier(self, filename: str) -> str:
        with self._lock:
            if filename in self._l1:
                return "L1"
            if filename in self._l2:
                return "L2"
            return "none"

    def get_tier_stats(self) -> dict:
        with self._lock:
            return {
                "l1_count": len(self._l1),
                "l2_count": len(self._l2),
                "l1_hits": self._l1_hits,
                "l2_hits": self._l2_hits,
            }

