class FileSystem(FileSystemBase):
    def __init__(self):
        self._files: dict[str, str] = {}    # path -> content
        self._dirs: set[str] = {"/"}        # set of directory paths

    def mkdir(self, path: str) -> bool:
        if path in self._dirs:
            return False
        self._dirs.add(path)
        return True

    def write_file(self, path: str, content: str) -> None:
        self._files[path] = content

    def read_file(self, path: str) -> str:
        return self._files.get(path, "")

    def delete(self, path: str) -> bool:
        if path in self._files:
            del self._files[path]
            return True
        if path in self._dirs and path != "/":
            self._dirs.discard(path)
            return True
        return False

    def ls(self, path: str) -> list:
        if path not in self._dirs:
            return []
        prefix = path.rstrip("/") + "/"
        results = set()
        for f in self._files:
            if f.startswith(prefix):
                rest = f[len(prefix):]
                if "/" not in rest:
                    results.add(rest)
        for d in self._dirs:
            if d != path and d.startswith(prefix):
                rest = d[len(prefix):]
                if "/" not in rest:
                    results.add(rest)
        return sorted(results)

    def get_size(self, path: str) -> int:
        if path in self._files:
            return len(self._files[path])
        if path in self._dirs:
            prefix = path.rstrip("/") + "/"
            total = 0
            for f, content in self._files.items():
                if f.startswith(prefix):
                    total += len(content)
            return total
        return 0

    def find(self, root: str, name: str) -> list:
        results = []
        prefix = root.rstrip("/") + "/"
        for f in self._files:
            if f.startswith(prefix) or f == root:
                fname = f.rsplit("/", 1)[-1]
                if fname == name:
                    results.append(f)
        for d in self._dirs:
            if (d.startswith(prefix) or d == root) and d != root:
                dname = d.rsplit("/", 1)[-1]
                if dname == name:
                    results.append(d)
        return sorted(results)

    def move(self, src: str, dst: str) -> bool:
        # src must exist
        if src not in self._files and src not in self._dirs:
            return False
        # dst must not already exist
        if dst in self._files or dst in self._dirs:
            return False
        if src in self._files:
            content = self._files.pop(src)
            self._files[dst] = content
        else:
            # moving a directory: move it and all contents
            self._dirs.discard(src)
            self._dirs.add(dst)
            src_prefix = src.rstrip("/") + "/"
            dst_prefix = dst.rstrip("/") + "/"
            # update sub-dirs
            sub_dirs = [d for d in self._dirs if d.startswith(src_prefix)]
            for d in sub_dirs:
                self._dirs.discard(d)
                self._dirs.add(dst_prefix + d[len(src_prefix):])
            # update files
            sub_files = [(f, c) for f, c in self._files.items() if f.startswith(src_prefix)]
            for f, c in sub_files:
                del self._files[f]
                self._files[dst_prefix + f[len(src_prefix):]] = c
        return True

    def copy(self, src: str, dst: str) -> bool:
        # src must exist
        if src not in self._files and src not in self._dirs:
            return False
        # dst must not already exist
        if dst in self._files or dst in self._dirs:
            return False
        if src in self._files:
            self._files[dst] = self._files[src]
        else:
            # copying a directory: deep copy
            self._dirs.add(dst)
            src_prefix = src.rstrip("/") + "/"
            dst_prefix = dst.rstrip("/") + "/"
            for d in list(self._dirs):
                if d.startswith(src_prefix):
                    self._dirs.add(dst_prefix + d[len(src_prefix):])
            for f, c in list(self._files.items()):
                if f.startswith(src_prefix):
                    self._files[dst_prefix + f[len(src_prefix):]] = c
        return True

