            src_prefix = src.rstrip("/") + "/"
            dst_prefix = dst.rstrip("/") + "/"
            for d in list(self._dirs):
                if d.startswith(src_prefix):
                    self._dirs.add(dst_prefix + d[len(src_prefix):])
            for f, c in list(self._files.items()):
                if f.startswith(src_prefix):
                    self._files[dst_prefix + f[len(src_prefix):]] = c
        return True

    def set_owner(self, path: str, owner: str) -> None:
        self._owners[path] = owner

    def set_mode(self, path: str, mode: str) -> None:
        self._modes[path] = mode

    def can_read(self, path: str, user: str) -> bool:
        # Owner can always read
        owner = self._owners.get(path)
        if owner == user:
            return True
        # If no mode set, default is world-readable (True)
        mode = self._modes.get(path)
        if mode is None:
            return True
        # mode is a string like "rwx" or "r--" or "---"
        # world read = first char is 'r'
        return mode[0] == 'r'

    def can_write(self, path: str, user: str) -> bool:
        # Owner can always write
        owner = self._owners.get(path)
        if owner == user:
            return True
        # If no mode set, default is world-writable (True)
        mode = self._modes.get(path)
        if mode is None:
            return True
        # world write = second char is 'w'
        return len(mode) > 1 and mode[1] == 'w'

