class FileSystem(FileSystemBase):
    def __init__(self):
        self._files: dict[str, str] = {}    # path -> content
        self._dirs: set[str] = {"/"}        # set of directory paths
        self._owners: dict[str, str] = {}   # path -> owner
        self._modes: dict[str, str] = {}    # path -> mode string
        self._symlinks: dict[str, str] = {} # link_path -> target
        self._mounts: dict[str, str] = {}   # mount_point -> fs_label

    def mkdir(self, path: str) -> bool:
        if path in self._dirs:
            return False
        self._dirs.add(path)
        return True

    def write_file(self, path: str, content: str) -> None:
        # Resolve symlinks before writing
        real_path = self._resolve_path(path)
        self._files[real_path] = content

    def read_file(self, path: str) -> str:
        real_path = self._resolve_path(path)
        return self._files.get(real_path, "")

    def delete(self, path: str) -> bool:
        if path in self._files:
            del self._files[path]
            self._owners.pop(path, None)
            self._modes.pop(path, None)
            return True
        if path in self._dirs and path != "/":
            self._dirs.discard(path)
            return True
        return False

    def ls(self, path: str) -> list:
        if path not in self._dirs:
            return []
        prefix = path.rstrip("/") + "/"
        results = set()
        for f in self._files:
            if f.startswith(prefix):
                rest = f[len(prefix):]
                if "/" not in rest:
                    results.add(rest)
        for d in self._dirs:
            if d != path and d.startswith(prefix):
                rest = d[len(prefix):]
                if "/" not in rest:
                    results.add(rest)
        return sorted(results)

    def get_size(self, path: str) -> int:
        if path in self._files:
            return len(self._files[path])
        if path in self._dirs:
            prefix = path.rstrip("/") + "/"
            total = 0
            for f, content in self._files.items():
                if f.startswith(prefix):
                    total += len(content)
            return total
        return 0

    def find(self, root: str, name: str) -> list:
        results = []
        prefix = root.rstrip("/") + "/"
        for f in self._files:
            if f.startswith(prefix) or f == root:
                fname = f.rsplit("/", 1)[-1]
                if fname == name:
                    results.append(f)
        for d in self._dirs:
            if (d.startswith(prefix) or d == root) and d != root:
                dname = d.rsplit("/", 1)[-1]
                if dname == name:
                    results.append(d)
        return sorted(results)

    def move(self, src: str, dst: str) -> bool:
        if src not in self._files and src not in self._dirs:
            return False
        if dst in self._files or dst in self._dirs:
            return False
        if src in self._files:
            self._files[dst] = self._files.pop(src)
            if src in self._owners:
                self._owners[dst] = self._owners.pop(src)
            if src in self._modes:
                self._modes[dst] = self._modes.pop(src)
        else:
            self._dirs.discard(src)
            self._dirs.add(dst)
            src_prefix = src.rstrip("/") + "/"
            dst_prefix = dst.rstrip("/") + "/"
            sub_dirs = [d for d in self._dirs if d.startswith(src_prefix)]
            for d in sub_dirs:
                self._dirs.discard(d)
                self._dirs.add(dst_prefix + d[len(src_prefix):])
            sub_files = [(f, c) for f, c in self._files.items() if f.startswith(src_prefix)]
            for f, c in sub_files:
                del self._files[f]
                self._files[dst_prefix + f[len(src_prefix):]] = c
        return True

    def copy(self, src: str, dst: str) -> bool:
        if src not in self._files and src not in self._dirs:
            return False
        if dst in self._files or dst in self._dirs:
            return False
        if src in self._files:
            self._files[dst] = self._files[src]
        else:
            self._dirs.add(dst)
            src_prefix = src.rstrip("/") + "/"
            dst_prefix = dst.rstrip("/") + "/"
            for d in list(self._dirs):
                if d.startswith(src_prefix):
                    self._dirs.add(dst_prefix + d[len(src_prefix):])
            for f, c in list(self._files.items()):
                if f.startswith(src_prefix):
                    self._files[dst_prefix + f[len(src_prefix):]] = c
        return True

    def set_owner(self, path: str, owner: str) -> None:
        self._owners[path] = owner

    def set_mode(self, path: str, mode: str) -> None:
        self._modes[path] = mode

    def can_read(self, path: str, user: str) -> bool:
        owner = self._owners.get(path)
        if owner == user:
            return True
        mode = self._modes.get(path)
        if mode is None:
            return True
        return mode[0] == 'r'

    def can_write(self, path: str, user: str) -> bool:
        owner = self._owners.get(path)
        if owner == user:
            return True
        mode = self._modes.get(path)
        if mode is None:
            return True
        return len(mode) > 1 and mode[1] == 'w'

    def _resolve_path(self, path: str, visited: set = None) -> str:
        """Follow symlinks, returning the real path."""
        if visited is None:
            visited = set()
        if path in visited:
            raise ValueError("Symlink cycle detected")
        if path in self._symlinks:
            visited.add(path)
            return self._resolve_path(self._symlinks[path], visited)
        return path

    def symlink(self, target: str, link_path: str) -> bool:
        """Create symlink at link_path pointing to target.
        Return False if link_path already exists."""
        if link_path in self._files or link_path in self._dirs or link_path in self._symlinks:
            return False
        self._symlinks[link_path] = target
        return True

    def resolve(self, path: str) -> str:
        """Resolve symlinks recursively. Raise if cycle detected."""
        return self._resolve_path(path)

    def mount(self, mount_point: str, fs_label: str) -> bool:
        """Mount a virtual filesystem at mount_point. Return False if occupied."""
        # mount_point must be an existing directory (not a file, not already mounted)
        if mount_point not in self._dirs:
            return False
        if mount_point in self._mounts:
            return False
        self._mounts[mount_point] = fs_label
        return True

