import time

class FileSystem(FileSystemBase):
    def __init__(self):
        self._files: dict[str, str] = {}    # path -> content
        self._dirs: set[str] = {"/"}        # set of directory paths
        self._owners: dict[str, str] = {}   # path -> owner
        self._modes: dict[str, str] = {}    # path -> mode string
        self._symlinks: dict[str, str] = {} # link_path -> target
        self._mounts: dict[str, str] = {}   # mount_point -> fs_label
        self._quotas: dict[str, int] = {}   # owner -> max_bytes
        self._audit_log: dict[str, list] = {}  # path -> list of (ts, user, op)

    def _resolve_path(self, path: str, visited: set = None) -> str:
        if visited is None:
            visited = set()
        if path in visited:
            raise ValueError("Symlink cycle detected")
        if path in self._symlinks:
            visited.add(path)
            return self._resolve_path(self._symlinks[path], visited)
        return path

    def mkdir(self, path: str) -> bool:
        if path in self._dirs:
            return False
        self._dirs.add(path)
        return True

    def write_file(self, path: str, content: str) -> None:
        real_path = self._resolve_path(path)
        old_size = len(self._files.get(real_path, ""))
        new_size = len(content)
        # Check if total FS bytes after write would exceed any quota
        total_before = sum(len(c) for c in self._files.values())
        total_after = total_before - old_size + new_size
        for q_owner, q_limit in self._quotas.items():
            if total_after > q_limit:
                return False
        self._files[real_path] = content
        owner = self._owners.get(real_path, "system")
        self._audit_log.setdefault(real_path, []).append((time.time(), owner, "write"))
        return None

    def read_file(self, path: str) -> str:
        real_path = self._resolve_path(path)
        return self._files.get(real_path, "")

    def delete(self, path: str) -> bool:
        if path in self._files:
            owner = self._owners.get(path, "system")
            del self._files[path]
            self._owners.pop(path, None)
            self._modes.pop(path, None)
            self._audit_log.setdefault(path, []).append((time.time(), owner, "delete"))
            return True
        if path in self._dirs and path != "/":
            self._dirs.discard(path)
