from collections import deque

class RateLimiter(RateLimiterBase):
    def __init__(self, max_requests: int, window_ms: int):
        self._max_requests = max_requests
        self._window_ms = window_ms
        self._logs: dict[str, deque] = {}
        self._custom_limits: dict[str, int] = {}
        self._burst: int = 0
        self._penalty_ms: int = 0
        # Maps user_id -> cooldown_expiry_timestamp (ms)
        self._cooldowns: dict[str, int] = {}
        # Track burst: user_id -> (last_timestamp, count_at_that_timestamp)
        self._burst_tracker: dict[str, tuple[int, int]] = {}

    def _get_log(self, user_id: str) -> deque:
        if user_id not in self._logs:
            self._logs[user_id] = deque()
        return self._logs[user_id]

    def _get_limit(self, user_id: str) -> int:
        return self._custom_limits.get(user_id, self._max_requests)

    def allow_request(self, user_id: str, timestamp: int) -> bool:
        # Check penalty/cooldown first
        if timestamp < self._cooldowns.get(user_id, 0):
            return False

        # Sliding window check
        dq = self._get_log(user_id)
        cutoff = timestamp - self._window_ms
        while dq and dq[0] <= cutoff:
            dq.popleft()
        if len(dq) >= self._get_limit(user_id):
            return False

        # Burst check: count requests at same timestamp
        if self._burst > 0:
            last_ts, burst_count = self._burst_tracker.get(user_id, (-1, 0))
            if last_ts == timestamp:
                burst_count += 1
            else:
                burst_count = 1
            self._burst_tracker[user_id] = (timestamp, burst_count)
            if burst_count > self._burst:
                # Trigger penalty
                self._cooldowns[user_id] = timestamp + self._penalty_ms
                return False

        dq.append(timestamp)
        return True

    def get_usage(self, user_id: str, timestamp: int) -> int:
        if user_id not in self._logs:
            return 0
        dq = self._logs[user_id]
        cutoff = timestamp - self._window_ms
        while dq and dq[0] <= cutoff:
            dq.popleft()
        return len(dq)

    def set_user_limit(self, user_id: str, limit: int) -> None:
        self._custom_limits[user_id] = limit

    def get_user_limit(self, user_id: str) -> int:
        return self._custom_limits.get(user_id, self._max_requests)

    def set_burst(self, burst: int, penalty_seconds: int) -> None:
        self._burst = burst
        self._penalty_ms = penalty_seconds * 1000

    def is_penalized(self, user_id: str, timestamp: int) -> bool:
        return timestamp < self._cooldowns.get(user_id, 0)

