from collections import deque

class RateLimiter(RateLimiterBase):
    def __init__(self, max_requests: int, window_ms: int):
        self._max_requests = max_requests
        self._window_ms = window_ms
        self._logs: dict[str, deque] = {}
        self._custom_limits: dict[str, int] = {}
        self._burst: int = 0
        self._penalty_ms: int = 0
        self._cooldowns: dict[str, int] = {}
        self._burst_tracker: dict[str, tuple[int, int]] = {}
        # Adaptive: user_id -> deque of (timestamp, success: bool)
        self._outcomes: dict[str, deque] = {}
        # user_id -> current adaptive limit override (None = use max_requests)
        self._adaptive_limits: dict[str, int] = {}

    def _get_log(self, user_id: str) -> deque:
        if user_id not in self._logs:
            self._logs[user_id] = deque()
        return self._logs[user_id]

    def _get_limit(self, user_id: str) -> int:
        return self._adaptive_limits.get(
            user_id,
            self._custom_limits.get(user_id, self._max_requests)
        )

    def allow_request(self, user_id: str, timestamp: int) -> bool:
        if timestamp < self._cooldowns.get(user_id, 0):
            return False
        dq = self._get_log(user_id)
        cutoff = timestamp - self._window_ms
        while dq and dq[0] <= cutoff:
            dq.popleft()
        if len(dq) >= self._get_limit(user_id):
            return False
        if self._burst > 0:
            last_ts, burst_count = self._burst_tracker.get(user_id, (-1, 0))
            if last_ts == timestamp:
                burst_count += 1
            else:
                burst_count = 1
            self._burst_tracker[user_id] = (timestamp, burst_count)
            if burst_count > self._burst:
                self._cooldowns[user_id] = timestamp + self._penalty_ms
                return False
        dq.append(timestamp)
        return True

    def get_usage(self, user_id: str, timestamp: int) -> int:
        if user_id not in self._logs:
            return 0
        dq = self._logs[user_id]
        cutoff = timestamp - self._window_ms
        while dq and dq[0] <= cutoff:
            dq.popleft()
        return len(dq)

    def set_user_limit(self, user_id: str, limit: int) -> None:
        self._custom_limits[user_id] = limit

    def get_user_limit(self, user_id: str) -> int:
        return self._custom_limits.get(user_id, self._max_requests)

    def set_burst(self, burst: int, penalty_seconds: int) -> None:
        self._burst = burst
        self._penalty_ms = penalty_seconds * 1000

    def is_penalized(self, user_id: str, timestamp: int) -> bool:
        return timestamp < self._cooldowns.get(user_id, 0)

    def get_tokens(self, user_id: str, current_time: float) -> float:
        if user_id not in self._logs:
            return float(self._max_requests)
        dq = self._logs[user_id]
        ts = int(current_time)
        cutoff = ts - self._window_ms
        count = sum(1 for t in dq if t > cutoff)
        return max(0.0, float(self._max_requests) - count)

    def export_state(self) -> dict:
        state = {}
        for user_id, dq in self._logs.items():
            state[user_id] = list(dq)
        return state

    def sync_state(self, other_state: dict) -> None:
        for user_id, other_timestamps in other_state.items():
            if user_id not in self._logs:
                self._logs[user_id] = deque(sorted(other_timestamps))
            else:
                local = set(self._logs[user_id])
                merged = sorted(set(other_timestamps) | local)
                self._logs[user_id] = deque(merged)

    def record_outcome(self, user_id: str, success: bool, timestamp: int) -> None:
        """Record whether a request succeeded or failed, then update adaptive limit."""
        if user_id not in self._outcomes:
            self._outcomes[user_id] = deque()
        self._outcomes[user_id].append((timestamp, success))
        # Update adaptive limit based on recent outcomes
        self._update_adaptive_limit(user_id, timestamp)

    def _update_adaptive_limit(self, user_id: str, timestamp: int) -> None:
        """Recalculate adaptive limit for user based on recent error rate."""
        outcomes = self._outcomes.get(user_id)
        if not outcomes:
            return
        # Look at all recorded outcomes (no window filtering for simplicity)
        total = len(outcomes)
        failures = sum(1 for _, s in outcomes if not s)
        error_rate = failures / total if total > 0 else 0.0

        base = self._custom_limits.get(user_id, self._max_requests)
        if error_rate > 0.5:
            # Reduce limit proportionally to error rate
            new_limit = max(1, int(base * (1.0 - error_rate)))
        else:
            new_limit = base
        self._adaptive_limits[user_id] = new_limit

    def get_adaptive_limit(self, user_id: str) -> int:
        """Return current adaptive limit for user based on recent error rate."""
        if user_id not in self._adaptive_limits:
            return self._custom_limits.get(user_id, self._max_requests)
        return self._adaptive_limits[user_id]

