import heapq

class TaskScheduler(TaskSchedulerBase):
    def __init__(self):
        # Unified heap: (run_at, -priority, counter, task_id, name)
        self._heap: list = []
        self._task_ids: set = set()
        self._cancelled: set = set()
        self._counter = 0

    def _push(self, task_id: str, name: str, priority: int, run_at: int) -> None:
        heapq.heappush(self._heap, (run_at, -priority, self._counter, task_id, name))
        self._counter += 1

    def add_task(self, task_id: str, name: str, priority: int) -> bool:
        if task_id in self._task_ids:
            return False
        self._task_ids.add(task_id)
        self._push(task_id, name, priority, run_at=0)
        return True

    def run_next(self) -> str | None:
        # Pop highest-priority task regardless of run_at
        # Need to scan all, picking highest priority (-priority lowest in tuple)
        # But heap is sorted by (run_at, -priority, counter), so we can't just pop top
        # Instead, extract all, find best, re-push rest
        if not self._heap:
            return None
        candidates = []
        while self._heap:
            candidates.append(heapq.heappop(self._heap))
        # Sort by (-priority, counter) to find best: lowest -priority first = highest priority
        candidates.sort(key=lambda e: (e[1], e[2]))
        result = None
        for entry in candidates:
            run_at, neg_pri, counter, task_id, name = entry
            if task_id not in self._cancelled and result is None:
                result = name
            elif task_id not in self._cancelled:
                heapq.heappush(self._heap, entry)
            # cancelled ones are dropped
        return result

    def cancel_task(self, task_id: str) -> bool:
        if task_id not in self._task_ids:
            return False
        self._cancelled.add(task_id)
        return True

    def add_task_at(self, task_id: str, name: str, priority: int, run_at: int) -> bool:
        if task_id in self._task_ids:
            return False
        self._task_ids.add(task_id)
        self._push(task_id, name, priority, run_at=run_at)
        return True

    def run_next_at(self, current_time: int) -> str | None:
        # Among tasks with run_at <= current_time, pick highest priority
        due = []
        not_due = []
        while self._heap:
            entry = heapq.heappop(self._heap)
            if entry[0] <= current_time:
                due.append(entry)
            else:
                not_due.append(entry)

        # Re-push not-due
        for entry in not_due:
            heapq.heappush(self._heap, entry)

        if not due:
            return None

        # Sort due by (-priority, counter) — best first
        due.sort(key=lambda e: (e[1], e[2]))

        result = None
        for entry in due:
            run_at, neg_pri, counter, task_id, name = entry
            if task_id not in self._cancelled and result is None:
                result = name
            elif task_id not in self._cancelled:
                heapq.heappush(self._heap, entry)
            # cancelled ones are dropped

        return result

