        candidates.sort(key=lambda e: (e[1], e[2]))
        result = None
        for entry in candidates:
            run_at, neg_pri, counter, task_id, name = entry
            if task_id not in self._cancelled and result is None:
                result = name
            elif task_id not in self._cancelled:
                heapq.heappush(self._heap, entry)
        return result

