        if task_id in self._task_ids:
            return False
        self._task_ids.add(task_id)
        self._push(task_id, name, priority, run_at=run_at)
        return True

    def run_next_at(self, current_time: int) -> str | None:
        due = []
        not_due = []
        while self._heap:
            entry = heapq.heappop(self._heap)
            if entry[0] <= current_time:
                due.append(entry)
            else:
                not_due.append(entry)
        for entry in not_due:
            heapq.heappush(self._heap, entry)
        if not due:
            return None
        due.sort(key=lambda e: (e[1], e[2]))
        result = None
        for entry in due:
            run_at, neg_pri, counter, task_id, name = entry
            if task_id not in self._cancelled and result is None:
                result = name
                # If recurring, reschedule
                if task_id in self._recurring:
                    r_name, r_priority, r_interval = self._recurring[task_id]
                    self._push(task_id, r_name, r_priority, run_at=run_at + r_interval)
            elif task_id not in self._cancelled:
                heapq.heappush(self._heap, entry)
        return result

    def run_all(self, current_time: int) -> list:
        results = []
        while True:
            name = self.run_next_at(current_time)
            if name is None:
