            results.append(name)
        return results

    def peek_next(self, current_time: int) -> str | None:
        due = [(e[1], e[2], e[3], e[4]) for e in self._heap
               if e[0] <= current_time and e[3] not in self._cancelled]
        if not due:
            return None
        due.sort(key=lambda e: (e[0], e[1]))
        return due[0][3]

    def add_recurring(self, task_id: str, name: str, priority: int,
                      interval_ms: int, start_at: int = 0) -> bool:
        if task_id in self._task_ids:
            return False
        self._task_ids.add(task_id)
        self._recurring[task_id] = (name, priority, interval_ms)
        self._push(task_id, name, priority, run_at=start_at)
        return True

    def get_schedule(self) -> list:
        result = []
        for run_at, neg_pri, counter, task_id, name in self._heap:
            if task_id not in self._cancelled:
                result.append((run_at, task_id, name))
        result.sort(key=lambda e: e[0])
        return result

