from abc import ABC, abstractmethod

class TaskSchedulerBase(ABC):
    """Abstract base class for Task Scheduler."""

    # ── Level 1: Basic Queue ───────────────────────────────────────

    @abstractmethod
    def add_task(self, task_id: str, name: str, priority: int) -> bool:
        """Add task with given priority. Return False if task_id already exists.
        Lower priority number = higher urgency."""
        ...

    @abstractmethod
    def run_next(self) -> str | None:
        """Execute the highest-priority pending task. Return its name, or None if empty."""
        ...

    @abstractmethod
    def cancel_task(self, task_id: str) -> bool:
        """Cancel a pending task. Return False if not found or already executed."""
        ...

    # ── Level 2: Delayed Execution ─────────────────────────────────

    @abstractmethod
    def add_task_at(self, task_id: str, name: str, priority: int, run_at: int) -> bool:
        """Add task scheduled to run at a specific timestamp."""
        ...

    @abstractmethod
    def run_next_at(self, current_time: int) -> str | None:
        """Execute highest-priority task that is due (run_at <= current_time).
        Return its name, or None if no task is due."""
        ...

    # ── Level 3: Bulk Operations ───────────────────────────────────

    @abstractmethod
    def run_all(self, current_time: int) -> list:
        """Execute all due tasks in priority order. Return list of task names."""
        ...

    @abstractmethod
    def peek_next(self, current_time: int) -> str | None:
        """Return name of the next due task without executing it."""
        ...

    # ── Level 4: Recurring Tasks ───────────────────────────────────

    @abstractmethod
    def add_recurring(self, task_id: str, name: str, priority: int,
                      interval: int, start_at: int) -> bool:
        """Add a recurring task that re-schedules itself after each execution."""
        ...

    @abstractmethod
    def get_schedule(self) -> list:
        """Return list of (run_at, task_id, name) tuples for all pending tasks."""
        ...

    # ── Level 5: Dependency DAG ────────────────────────────────────

    @abstractmethod
    def add_task_with_deps(self, task_id: str, name: str, priority: int,
                           deps: list) -> bool:
        """Add task with dependency list. Task becomes runnable only when all deps complete.
        Return False if task_id exists or a dependency cycle is detected."""
        ...

    @abstractmethod
    def mark_done(self, task_id: str) -> list:
        """Mark task as completed. Return list of task_ids newly unblocked."""
        ...

    @abstractmethod
    def get_ready(self) -> list:
        """Return list of task_ids with all dependencies satisfied."""
        ...

    # ── Level 6: Worker Pool ───────────────────────────────────────

    @abstractmethod
    def register_worker(self, worker_id: str, capacity: int) -> None:
        """Register a worker with given task capacity."""
        ...

    @abstractmethod
    def assign_next(self, worker_id: str, current_time: int) -> str | None:
        """Assign the next due task to worker. Return task_id or None if none available."""
        ...

    @abstractmethod
    def complete_task(self, worker_id: str, task_id: str) -> bool:
        """Mark task as completed by worker. Return False if not assigned to this worker."""
        ...

    @abstractmethod
    def get_worker_stats(self, worker_id: str) -> dict:
        """Return dict with keys: assigned, completed, capacity."""
        ...

