    def add_task(self, task_id: str, name: str, priority: int) -> bool:
        if task_id in self._task_ids:
            return False
        self._task_ids.add(task_id)
        self._push(task_id, name, priority, run_at=0)
        return True

    def run_next(self) -> str | None:
        if not self._heap:
            return None
        candidates = []
        while self._heap:
            candidates.append(heapq.heappop(self._heap))
        candidates.sort(key=lambda e: (e[1], e[2]))
