            run_at, neg_pri, counter, task_id, name = entry
            if task_id not in self._cancelled and result is None:
                result = name
            elif task_id not in self._cancelled:
                heapq.heappush(self._heap, entry)
        return result

    def cancel_task(self, task_id: str) -> bool:
        if task_id not in self._task_ids:
            return False
        self._cancelled.add(task_id)
        return True

    def add_task_at(self, task_id: str, name: str, priority: int, run_at: int) -> bool:
        if task_id in self._task_ids:
            return False
        self._task_ids.add(task_id)
        self._push(task_id, name, priority, run_at=run_at)
        return True

    def run_next_at(self, current_time: int) -> str | None:
        due = []
        not_due = []
        while self._heap:
            entry = heapq.heappop(self._heap)
            if entry[0] <= current_time:
                due.append(entry)
            else:
                not_due.append(entry)
        for entry in not_due:
            heapq.heappush(self._heap, entry)
        if not due:
            return None
        due.sort(key=lambda e: (e[1], e[2]))
        result = None
        for entry in due:
            run_at, neg_pri, counter, task_id, name = entry
            if task_id not in self._cancelled and result is None:
                result = name
                if task_id in self._recurring:
                    r_name, r_priority, r_interval = self._recurring[task_id]
                    self._push(task_id, r_name, r_priority, run_at=run_at + r_interval)
            elif task_id not in self._cancelled:
                heapq.heappush(self._heap, entry)
        return result

    def run_all(self, current_time: int) -> list:
        results = []
        while True:
            name = self.run_next_at(current_time)
            if name is None:
                break
            results.append(name)
        return results

    def peek_next(self, current_time: int) -> str | None:
        due = [(e[1], e[2], e[3], e[4]) for e in self._heap
               if e[0] <= current_time and e[3] not in self._cancelled]
        if not due:
            return None
        due.sort(key=lambda e: (e[0], e[1]))
        return due[0][3]

    def add_recurring(self, task_id: str, name: str, priority: int,
                      interval_ms: int, start_at: int = 0) -> bool:
        if task_id in self._task_ids:
            return False
        self._task_ids.add(task_id)
        self._recurring[task_id] = (name, priority, interval_ms)
        self._push(task_id, name, priority, run_at=start_at)
        return True

    def get_schedule(self) -> list:
        result = []
        for run_at, neg_pri, counter, task_id, name in self._heap:
            if task_id not in self._cancelled:
                result.append((run_at, task_id, name))
        result.sort(key=lambda e: e[0])
        return result

    def add_task_with_deps(self, task_id: str, name: str, priority: int,
                           deps: list) -> bool:
        if task_id in self._task_ids:
            return False
        self._task_ids.add(task_id)
        remaining_deps = set(d for d in deps if d not in self._done)
        self._deps[task_id] = remaining_deps
        if not remaining_deps:
            self._push(task_id, name, priority, run_at=0)
        else:
            self._blocked[task_id] = (name, priority)
            for dep in remaining_deps:
                self._dependents.setdefault(dep, set()).add(task_id)
        return True

    def mark_done(self, task_id: str) -> list:
        if task_id not in self._task_ids:
            return []
        self._done.add(task_id)
        newly_unblocked = []
        for waiting_id in list(self._dependents.get(task_id, set())):
            self._deps[waiting_id].discard(task_id)
            if not self._deps[waiting_id] and waiting_id in self._blocked:
                name, priority = self._blocked.pop(waiting_id)
                self._push(waiting_id, name, priority, run_at=0)
                newly_unblocked.append(waiting_id)
        return newly_unblocked

    def get_ready(self) -> list:
        ready = []
        for run_at, neg_pri, counter, task_id, name in self._heap:
            if task_id not in self._cancelled:
                ready.append(task_id)
        return ready

    def register_worker(self, worker_id: str, capacity: int = 1) -> None:
        self._workers[worker_id] = {
            'capacity': capacity,
            'assigned': 0,
            'completed': 0,
            'current_tasks': set(),
        }

    def assign_next(self, worker_id: str, current_time: int) -> str | None:
        if worker_id not in self._workers:
            return None
        worker = self._workers[worker_id]
        # Check capacity
        if len(worker['current_tasks']) >= worker['capacity']:
            return None
        # Find next due, non-assigned, non-cancelled task
        due = []
        not_due = []
        while self._heap:
            entry = heapq.heappop(self._heap)
            if entry[0] <= current_time:
                due.append(entry)
            else:
                not_due.append(entry)
        for entry in not_due:
            heapq.heappush(self._heap, entry)

        if not due:
            return None

        due.sort(key=lambda e: (e[1], e[2]))
        result_name = None
        result_task_id = None
        for entry in due:
            run_at, neg_pri, counter, task_id, name = entry
            if (task_id not in self._cancelled
                    and task_id not in self._assigned
                    and result_name is None):
                result_name = name
                result_task_id = task_id
                # Don't push back — it's assigned
            elif task_id not in self._cancelled:
                heapq.heappush(self._heap, entry)
            # cancelled and already-assigned dropped from heap (they'll be handled elsewhere)

        if result_task_id is not None:
            self._assigned[result_task_id] = worker_id
            worker['current_tasks'].add(result_task_id)
            worker['assigned'] += 1

        return result_name

    def complete_task(self, worker_id: str, task_id: str) -> bool:
        if worker_id not in self._workers:
            return False
        if self._assigned.get(task_id) != worker_id:
            return False
        worker = self._workers[worker_id]
        worker['current_tasks'].discard(task_id)
        worker['completed'] += 1
        del self._assigned[task_id]
        self._done.add(task_id)
        return True

    def get_worker_stats(self, worker_id: str) -> dict:
        if worker_id not in self._workers:
            return {}
        w = self._workers[worker_id]
        return {
            'assigned': w['assigned'],
            'completed': w['completed'],
            'capacity': w['capacity'],
        }

