import time

def put(store, key, value, ttl):
    expire_at = time.time() + ttl
    store[key] = (value, expire_at)

def get(store, key):
    entry = store.get(key)
    if entry is None:
        return None
    value, expire_at = entry
    if time.time() > expire_at:
        del store[key]
        return None
    return value

