import heapq
heap = []
removed = set()

def push(item, priority):
    heapq.heappush(heap, (priority, item))

def remove(item):
    removed.add(item)   # mark; don't touch heap

def pop():
    while heap:
        priority, item = heapq.heappop(heap)
        if item not in removed:
            return priority, item
    return None, None
